UPDATE MCP_USER SET
    LOGIN_FAIL_COUNT = #{loginFailCount}
WHERE USERID = #{userId}

UPDATE MCP_USER SET
                    BIRTHDAY = #{birthday},
                    GENDER = #{gender}
WHERE USERID = #{userId}

mapper.select:
SELECT /*LoginMapper.dormancyLoginProcess */ USER_ID as USERID , LOGIN_PWD as PASSWORD , NM as NAME , AUT_CODE as AUTH_CODE , PIN , EMAIL , ZIPCD as POST , ADDRESS , ADDRESS_DTL , MOBILE_NO , CTN as CONTACT_NO , BIRTHDAY , GENDER , CRET_DT as SYS_RDATE , AMD_DT as SYS_UDATE , LOGIN_DT as SYS_LDATE , LOGIN_CNT as LOGIN_COUNT , USER_STTUS as STATUS , CUST_NO as CUST_NUM , AUTH_KEY , USER_DIV as USER_DIVISION , EMAIL_CODE , ADDRESS_BJD , REVOCATION_DATE , PWD_CHG_LAST_DT as PWD_CHG_DT , MONTHS_BETWEEN(SYSDATE , PWD_CHG_LAST_DT) AS MON_CNT , CUSTOMER_ID FROM NMCP_USER_HST WHERE USER_ID = #{userId}
AND LOGIN_PWD = #{passWord}
AND USER_STTUS = '4' AND HST_CHG_DT IS NULL

SELECT AUTO_LOGIN_SEQ ,PLATFORM_CD ,USER_ID ,LOGIN_DIV_CD ,TOKEN ,TOKEN_REG_DT ,TOKEN_VALID_PERIOD ,ROWNUM RNUM FROM ( SELECT AUTO_LOGIN_SEQ ,PLATFORM_CD ,USER_ID ,LOGIN_DIV_CD ,TOKEN ,TOKEN_REG_DT ,TOKEN_VALID_PERIOD ,ROWNUM RNUM FROM NMCP_AUTO_LOGIN_TXN WHERE 1=1
AND TOKEN = #{token}
AND USER_ID = #{userId}
ORDER BY AUTO_LOGIN_SEQ DESC ) WHERE ROWNUM = 1

mapper.insert:

    SELECT NVL(MAX(AUTO_LOGIN_SEQ), 0) + 1 FROM NMCP_AUTO_LOGIN_TXN

INSERT INTO NMCP_AUTO_LOGIN_TXN(
AUTO_LOGIN_SEQ
, PLATFORM_CD
, USER_ID
, LOGIN_DIV_CD
, TOKEN
, TOKEN_REG_DT
, TOKEN_VALID_PERIOD
, CRET_DT
, AMD_DT
) VALUES (
#{autoLoginSeq}
, #{platformCd}
, #{userId}
, #{loginDivCd}
, #{token}
, SYSDATE
, #{tokenValidPeriod}
, SYSDATE
, SYSDATE
)

mapper.select:
SELECT USERID, PASSWORD, NAME, AUTH_CODE, PIN, EMAIL, POST, ADDRESS, ADDRESS_DTL, MOBILE_NO, CONTACT_NO, BIRTHDAY, GENDER, SYS_RDATE, SYS_UDATE, SYS_LDATE, LOGIN_COUNT, STATUS, CUST_NUM, AUTH_KEY, USER_DIVISION, EMAIL_CODE, ADDRESS_BJD, REVOCATION_DATE FROM ( SELECT USERID, PASSWORD, NAME, AUTH_CODE, PIN, EMAIL, POST, ADDRESS, ADDRESS_DTL, MOBILE_NO, CONTACT_NO, BIRTHDAY, GENDER, SYS_RDATE, SYS_UDATE, SYS_LDATE, LOGIN_COUNT, STATUS, CUST_NUM, AUTH_KEY, USER_DIVISION, EMAIL_CODE, ADDRESS_BJD, REVOCATION_DATE FROM MCP_USER WHERE pin = #{pin}
AND UPPER(NAME) = UPPER(TRIM(#{name}))
ORDER BY SYS_RDATE DESC ) WHERE ROWNUM = 1

SELECT USERID, PASSWORD, NAME, AUTH_CODE, PIN, EMAIL, POST, ADDRESS, ADDRESS_DTL, MOBILE_NO, CONTACT_NO, BIRTHDAY, GENDER, SYS_RDATE, SYS_UDATE, SYS_LDATE, LOGIN_COUNT, STATUS, CUST_NUM, AUTH_KEY, USER_DIVISION, EMAIL_CODE, ADDRESS_BJD, REVOCATION_DATE FROM ( SELECT USER_ID USERID, LOGIN_PWD PASSWORD, NM NAME, AUT_CODE AUTH_CODE, PIN, EMAIL, ZIPCD POST, ADDRESS, ADDRESS_DTL, MOBILE_NO, CTN CONTACT_NO, BIRTHDAY, GENDER, CRET_DT SYS_RDATE, AMD_DT SYS_UDATE, LOGIN_DT SYS_LDATE, LOGIN_CNT LOGIN_COUNT, USER_STTUS STATUS, CUST_NO CUST_NUM, AUTH_KEY, USER_DIV USER_DIVISION, EMAIL_CODE, ADDRESS_BJD, REVOCATION_DATE FROM NMCP_USER_HST WHERE pin = #{pin}
AND UPPER(NM) = UPPER(TRIM(#{name}))
AND USER_STTUS = '4' AND HST_CHG_DT IS NULL ORDER BY SYS_RDATE DESC ) WHERE ROWNUM = 1

SELECT COUNT(*)
FROM NMCP_IP_LIMIT
WHERE SYSDATE < SYS_RDATE + (#{limitTime}/24/60/60)
AND ACCESS_IP = #{accessIp}


        AND LIMIT_TYPE = #{limitType}


        AND NVL(LIMIT_TYPE,'NULL') != 'RECAPTCHA'

mapper.insert:
INSERT INTO NMCP_IP_LIMIT
(
LIMIT_SEQ
, ACCESS_IP
, USER_ID
, SYS_RDATE

    , LIMIT_TYPE

) VALUES
(
TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') || TRIM(TO_CHAR(NMCP_IP_LIMIT_SEQ.NEXTVAL, '000000'))
, #{accessIp}
, #{userId}
, SYSDATE

    , #{limitType}

)
